#include<bits/stdc++.h>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
typedef __int128 ll;
#define int ll
const int N=5e5+10,Mod=1e9+7;
struct nd{int a,b;}t1[N],t[N];
int n,nn,A=1,B=1;bool vis[N];long double qwq[N];
signed main()
{
	nn=read();rep(1,nn,i)t1[i].a=read();rep(1,nn,i)t1[i].b=read();
	rep(1,nn,i)if(t1[i].a==1){B+=t1[i].b;}else t[++n]=t1[i];
	rep(1,n,i)qwq[i]=(long double)(t[i].b+B)/t[i].a;
	long double mx=qwq[1];int idx=1;rep(2,n,i)if(qwq[i]>mx)mx=qwq[idx=i];
	if(B+t[idx].b>B*t[idx].a){B+=t[idx].b;vis[idx]=true;}
	rep(1,n,i)if(!vis[i])A=A*t[i].a%Mod;
	printf("%lld\n",(long long)(B*A%Mod));return 0;
}
